sql:
SELECT name, AVG(market_cap) AS average_market_cap
FROM cryptocurrencies
GROUP BY name;

SELECT c.symbol, c.name
FROM cryptocurrencies c
WHERE c.market_cap = (SELECT MAX(market_cap) FROM cryptocurrencies);

SELECT COUNT(*) AS total_trades
FROM trades
WHERE trade_type = 'buy';

SELECT metric_name, value
FROM platform_metrics
WHERE recorded_at > '2021-07-01 00:00:00';

SELECT AVG(market_cap) AS avg_higher_market_cap
FROM cryptocurrencies
WHERE market_cap > (SELECT AVG(market_cap) FROM cryptocurrencies);

SELECT trade_id
FROM trades
WHERE trade_type = 'buy';

SELECT read_status, COUNT(*) AS notification_count
FROM notifications
GROUP BY read_status;

SELECT title
FROM market_news
WHERE news_id = 1;

SELECT user_id
FROM notifications
WHERE read_status = 'unread';

SELECT AVG(th.market_impact) AS average_market_impact
FROM trade_history th
JOIN market_data md ON th.price_before = md.low AND th.price_after = md.high;

SELECT username
FROM users
WHERE user_id = 1;

SELECT rating
FROM user_feedback
WHERE rating > 3;

SELECT AVG(market_cap) AS average_market_cap_above_avg
FROM cryptocurrencies
WHERE market_cap > (
  SELECT AVG(market_cap)
  FROM cryptocurrencies
);

SELECT name, market_cap
FROM cryptocurrencies
WHERE market_cap = (SELECT MAX(market_cap) FROM cryptocurrencies);
